// ─── USGS Earthquake Processing & Trade Route Impact ───
// Assess whether earthquakes could impact critical trade infrastructure.

const CRITICAL_TRADE_ZONES = [
  { name: 'Suez Canal',       lat: 30.45, lon: 32.35, radiusKm: 500, routeCriticality: 0.95 },
  { name: 'Strait of Hormuz', lat: 26.57, lon: 56.25, radiusKm: 400, routeCriticality: 0.90 },
  { name: 'Panama Canal',     lat: 9.08,  lon: -79.68, radiusKm: 300, routeCriticality: 0.85 },
  { name: 'Taiwan Strait',    lat: 24.50, lon: 119.50, radiusKm: 500, routeCriticality: 0.85 },
  { name: 'Malacca Strait',   lat: 2.50,  lon: 101.50, radiusKm: 400, routeCriticality: 0.80 },
  { name: 'Gibraltar',        lat: 36.13, lon: -5.35,  radiusKm: 300, routeCriticality: 0.70 },
  // Major ports
  { name: 'Port of Shanghai', lat: 31.23, lon: 121.47, radiusKm: 200, routeCriticality: 0.75 },
  { name: 'Port of Singapore', lat: 1.26, lon: 103.84, radiusKm: 200, routeCriticality: 0.75 },
  { name: 'Port of Rotterdam', lat: 51.95, lon: 4.12,  radiusKm: 200, routeCriticality: 0.65 },
];

const NUCLEAR_TEST_SITES = [
  { name: 'Punggye-ri',    lat: 41.28, lon: 129.08, radiusKm: 100 },
  { name: 'Lop Nur',       lat: 41.39, lon: 89.03,  radiusKm: 100 },
  { name: 'Novaya Zemlya', lat: 73.37, lon: 54.78,  radiusKm: 100 },
];

function haversineKm(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = ((lat2 - lat1) * Math.PI) / 180;
  const dLon = ((lon2 - lon1) * Math.PI) / 180;
  const a = Math.sin(dLat / 2) ** 2 + Math.cos((lat1 * Math.PI) / 180) * Math.cos((lat2 * Math.PI) / 180) * Math.sin(dLon / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

const geojson = $input.item.json;
const features = geojson.features || [];

const earthquakes = features
  .filter(f => f?.properties && f?.geometry?.coordinates)
  .map(f => {
    const lat = f.geometry.coordinates[1];
    const lon = f.geometry.coordinates[0];
    const mag = f.properties.mag || 0;
    const depthKm = f.geometry.coordinates[2] || 0;

    // Check proximity to trade routes
    let nearestRoute = null;
    let routeDistance = Infinity;
    for (const zone of CRITICAL_TRADE_ZONES) {
      const km = haversineKm(lat, lon, zone.lat, zone.lon);
      if (km < zone.radiusKm && km < routeDistance) {
        nearestRoute = zone;
        routeDistance = km;
      }
    }

    // Check proximity to nuclear test sites
    let nearTestSite = false;
    let testSiteName = null;
    for (const site of NUCLEAR_TEST_SITES) {
      if (haversineKm(lat, lon, site.lat, site.lon) < site.radiusKm) {
        nearTestSite = true;
        testSiteName = site.name;
        break;
      }
    }

    // Risk score for customs
    let tradeImpactScore = 0;
    if (nearestRoute) {
      const magFactor = Math.min(1, mag / 9);
      const proximityFactor = 1 - (routeDistance / nearestRoute.radiusKm);
      tradeImpactScore = Math.round(magFactor * 0.5 * 100 + proximityFactor * nearestRoute.routeCriticality * 0.5 * 100);
    }

    return {
      id: String(f.id || ''),
      place: String(f.properties.place || ''),
      magnitude: mag,
      depthKm,
      location: { latitude: lat, longitude: lon },
      occurredAt: f.properties.time,
      sourceUrl: String(f.properties.url || ''),
      nearTradeRoute: nearestRoute ? nearestRoute.name : null,
      tradeRouteDistanceKm: nearestRoute ? Math.round(routeDistance) : null,
      tradeImpactScore,
      nearTestSite,
      testSiteName,
    };
  })
  .sort((a, b) => b.tradeImpactScore - a.tradeImpactScore);

const tradeRelevant = earthquakes.filter(e => e.tradeImpactScore > 0);

return {
  json: {
    earthquakes,
    summary: {
      total: earthquakes.length,
      tradeRelevant: tradeRelevant.length,
      nearTestSites: earthquakes.filter(e => e.nearTestSite).length,
      maxMagnitude: Math.max(...earthquakes.map(e => e.magnitude), 0),
    },
    processedAt: new Date().toISOString(),
  }
};
